external_knowledge:
; In this context, 'aggregate satisfaction statistics' refers to the total number of results, average satisfaction percentage, total sample size, maximum satisfaction rank, minimum confidence level, and maximum sample variance for each survey; 
; The year 1984 is specified because the analysis is focused on a specific time period; 
; The threshold of 5% average satisfaction percentage is used as a filter to exclude surveys with very low satisfaction levels.

sql:
SELECT SUM(sample_size) AS total_sample_size
FROM survey_locations
WHERE survey_id = 0;

SELECT demographic_id, AVG(sample_size) AS average_sample_size
FROM survey_demographics
GROUP BY demographic_id;

SELECT survey_id, demographic_id, response_rate
FROM survey_demographics
WHERE sample_size > 500;

SELECT survey_name, start_date, COUNT(*) OVER () AS total_completed_surveys
FROM surveys
WHERE survey_status = 'completed';
